interface CapturedRequest {
  method: string;
  path: string;
  search: string;
  headers: Record<string, string>;
  body: unknown;
}

function startMockSnykServer(
  responses: Record<string, { data: unknown; isCollection?: boolean }>,
): { url: string; server: Deno.HttpServer; requests: CapturedRequest[] } {
  const requests: CapturedRequest[] = [];
  const server = Deno.serve({ port: 0, onListen() {} }, async (req) => {
    const url = new URL(req.url);
    const path = url.pathname;

    // Capture the request (headers, method, path, query, parsed body).
    let reqBody: unknown = null;
    if (req.body) {
      const text = await req.text();
      if (text) {
        try {
          reqBody = JSON.parse(text);
        } catch {
          reqBody = text;
        }
      }
    }
    requests.push({
      method: req.method,
      path,
      search: url.search,
      headers: Object.fromEntries(req.headers),
      body: reqBody,
    });

    for (const [pattern, { data, isCollection }] of Object.entries(responses)) {
      if (path.includes(pattern)) {
        const body = isCollection
          ? {
            data: Array.isArray(data) ? data : [data],
            jsonapi: { version: "1.0" },
            links: { self: path, next: null },
          }
          : {
            data,
            jsonapi: { version: "1.0" },
            links: { self: path },
          };
        return Response.json(body, {
          headers: { "content-type": "application/vnd.api+json" },
        });
      }
    }

    return new Response(
      JSON.stringify({
        jsonapi: { version: "1.0" },
        errors: [{ status: "404", detail: "Not found" }],
      }),
      { status: 404, headers: { "content-type": "application/vnd.api+json" } },
    );
  });

  const addr = server.addr as Deno.NetAddr;
  return { url: `http://localhost:${addr.port}`, server, requests };
}

function installFetchMock(mockUrl: string): () => void {
  const originalFetch = globalThis.fetch;
  globalThis.fetch = (input, init) => {
    const reqUrl = typeof input === "string" ? input : input.toString();
    const newUrl = reqUrl.replace("https://api.snyk.io/rest", mockUrl);
    return originalFetch(newUrl, init);
  };
  return () => {
    globalThis.fetch = originalFetch;
  };
}

